const body = $input.first().json;
const tweets = Array.isArray(body.tweets) ? body.tweets : [];
const normalized = tweets.map((tweet) => {
  const id = tweet.id ?? tweet.tweet_id ?? tweet.rest_id ?? '';
  const author = tweet.author ?? tweet.user ?? {};
  return {
    id,
    url: tweet.url ?? (id ? `https://x.com/i/web/status/${id}` : ''),
    text: tweet.text ?? tweet.full_text ?? tweet.content ?? '',
    author: author.username ?? author.screen_name ?? author.name ?? '',
    created_at: tweet.created_at ?? tweet.created ?? tweet.timestamp ?? '',
    metrics: tweet.metrics ?? {}
  };
});
const digestLines = normalized.length === 0
  ? ['No matching X posts found for this query.']
  : normalized.map((tweet, index) => {
      const author = tweet.author ? ` by ${tweet.author}` : '';
      const link = tweet.url ? `\n${tweet.url}` : '';
      return `${index + 1}. ${tweet.text}${author}${link}`;
    });
return [{
  json: {
    query: $('Search Settings').first().json.query,
    results_count: normalized.length,
    has_more: Boolean(body.has_more),
    next_cursor: body.next_cursor ?? '',
    tweets: normalized,
    digest: digestLines.join('\n\n')
  }
}];
